import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule, Location } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { environment } from '../../../environments/environment';
import { Profile } from '../../core/models';
import { ToastService } from '../../core/services/toast.service';

const EMPTY_PROFILE: Profile = {
  id: '', name: '', jobTitle: '', employer: '', bio: '',
  pictureUrl: '', photos: [], distanceKm: 0, mutualConnections: 0,
};

@Component({
  selector: 'app-user-profile',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './user-profile.component.html',
  styleUrl: './user-profile.component.css',
})
export class UserProfileComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private location = inject(Location);
  private toast = inject(ToastService);
  private http = inject(HttpClient);
  private readonly apiUrl = environment.apiUrl;

  goBack(): void {
    this.location.back();
  }

  readonly userId = this.route.snapshot.paramMap.get('userId') ?? '';

  readonly reasons = signal<string[]>([
    'Inappropriate photos', 'Harassment or abuse', 'Fake or impersonated profile', 'Spam or solicitation', 'Off-platform scam',
  ]);

  readonly profile = signal<Profile>(EMPTY_PROFILE);
  readonly reportOpen = computed(() => this.route.snapshot.queryParamMap.get('modal') === 'report');

  readonly selectedReason = signal('');
  readonly details = signal('');
  readonly submitted = signal(false);

  ngOnInit(): void {
    this.http.get<Profile>(`${this.apiUrl}/users/${this.userId}`).subscribe({
      next: (p) => this.profile.set(p ?? EMPTY_PROFILE),
      error: () => this.profile.set(EMPTY_PROFILE),
    });
  }

  openReport(): void {
    this.router.navigate([], { queryParams: { modal: 'report' }, queryParamsHandling: 'merge' });
  }

  closeReport(): void {
    this.submitted.set(false);
    this.router.navigate([], { queryParams: { modal: null }, queryParamsHandling: 'merge' });
  }

  submitReport(): void {
    if (!this.selectedReason()) return;
    this.http
      .post(`${this.apiUrl}/reports`, {
        reportedId: this.profile().id || this.userId,
        reason: this.selectedReason(),
      })
      .subscribe({
        next: () => {
          this.submitted.set(true);
          this.toast.push('message', 'Report submitted', 'Our moderation team will review it shortly.');
          setTimeout(() => this.closeReport(), 1400);
        },
        error: () => {},
      });
  }
}
